require(StarterGui.UIClientScreenGUI.UIClient.Menus["Votekick Interface"])

local PreferredInput = require(StarterGui.UIClientScreenGUI.UIClient.State.PreferredInput)

if require(ReplicatedStorage.SharedModules.Core.PlaceModule).PlaceName ~= "Lobby" then
	return nil
end

local v2 = Fusion:scoped()
local v3 = v1.New(v2, {
	Buttons = {
		{
			Text = "Emote",
			Icon = "rbxassetid://83686327685482",
			Transparency = 0.5,
			Callback = function() --[[ Callback | Line: 23 ]]
				task.delay(0.01, _G.SATAN_EmoteButtonPressed)
			end,
			Visible = v2:Computed(function(p1) --[[ Line: 26 | Upvalues: PreferredInput (copy) ]]
				local isTouch = p1(PreferredInput) == Enum.PreferredInput.Touch

				return isTouch
			end)
		},
		{
			Text = "Achievements",
			Icon = "rbxassetid://87215182193778",
			Transparency = 0.5,
			Callback = function() --[[ Callback | Line: 35 ]]
				_G.SATAN_OPENACHIEVEMENTS()
			end
		},
		{
			Text = "Stats",
			Icon = "rbxassetid://122329231545864",
			Transparency = 0.5,
			Callback = function() --[[ Callback | Line: 42 ]]
				_G.SATAN_OPENSTATISTICS()
			end
		},
		{
			Text = "Shop",
			Icon = "rbxassetid://105964271202094",
			Transparency = 0.5,
			Callback = function() --[[ Callback | Line: 49 ]]
				_G.SATAN_OPENSHOP()
			end
		},
		{
			Text = "Settings",
			Icon = "rbxassetid://80509553540013",
			Transparency = 0.5,
			Callback = function() --[[ Callback | Line: 56 ]]
				_G.SATAN_TOGGLESETTINGS()
			end
		}
	}
})

v2:New("ScreenGui")({
	ResetOnSpawn = false,
	DisplayOrder = 51,
	Enabled = true,
	IgnoreGuiInset = false,
	ClipToDeviceSafeArea = false,
	ScreenInsets = v2:Computed(function(p1) --[[ Line: 68 | Upvalues: PreferredInput (copy) ]]
		if p1(PreferredInput) == Enum.PreferredInput.Touch then
			return Enum.ScreenInsets.TopbarSafeInsets
		end

		return Enum.ScreenInsets.CoreUISafeInsets
	end),
	Parent = Players.LocalPlayer.PlayerGui,
	[Fusion.Children] = { v3 }
}).ScreenInsets = if peek(PreferredInput) == Enum.PreferredInput.Touch then Enum.ScreenInsets.TopbarSafeInsets else Enum.ScreenInsets.CoreUISafeInsets

return nil

