			Part2.CanQuery = false
			Part2.CanTouch = false
			Part2.Anchored = true
			Part2.Material = Enum.Material.Metal
			Part2.Size = Vector3.new(0.01, 0.01, 0.01)
			Part2.Transparency = 1
			Part2.Parent = v7.Instance
			TweenService:Create(Part2, TweenInfo.new(math.random(1.87, 2.67), Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
				Size = Vector3.new(v11, v11, 0.01)
			}):Play()

			local Decal = Instance.new("Decal")

			Decal.Texture = t[math.random(1, #t)]
			Decal.Parent = Part2
			Decal.Color3 = Color3.fromRGB(400, 400, 400)
			game.Debris:AddItem(Part2, math.random(20, 40))
		end
	end
end

