return function() --[[ Line: 1 ]]
	local merge = require(script.Parent.merge)
	local None = require(script.Parent.Parent.None)

	it("should combine two or more dictionaries, where the last value overrides previous", function() --[[ Line: 7 | Upvalues: merge (copy) ]]
		local v1 = merge({
			hello = "roblox",
			goodbye = "world"
		}, {
			hello = "hello"
		})

		expect(v1).to.be.a("table")
		expect(v1.hello).to.equal("hello")
		expect(v1.goodbye).to.equal("world")
	end)
	it("should not modify the original dictionaries", function() --[[ Line: 20 | Upvalues: merge (copy) ]]
		local t = {
			hello = "roblox",
			goodbye = "world"
		}
		local t2 = {
			hello = "hello"
		}

		merge(t, t2)
		expect(t).to.be.a("table")
		expect(t2).to.be.a("table")
		expect(t.hello).to.equal("roblox")
		expect(t2.hello).to.equal("hello")
	end)
	it("should accept nil values", function() --[[ Line: 33 | Upvalues: merge (copy) ]]
		local t = {
			hello = "roblox",
			goodbye = "world"
		}
		local v1 = merge(t, nil)
		local v2 = merge(nil, t)

		expect(v1).to.be.a("table")
		expect(v1.hello).to.equal("roblox")
		expect(v1.goodbye).to.equal("world")
		expect(v2).to.be.a("table")
		expect(v2.hello).to.equal("roblox")
		expect(v2.goodbye).to.equal("world")
	end)
	it("should remove values set to None", function() --[[ Line: 50 | Upvalues: None (copy), merge (copy) ]]
		local v1 = merge({
			hello = "roblox",
			goodbye = "world"
		}, {
			goodbye = None
		})

		expect(v1).to.be.a("table")
		expect(v1.hello).to.equal("roblox")
		expect(v1.goodbye).to.equal(nil)
	end)
end

