	it("should combine two or more dictionaries, where the last value overrides previous, recursively", function() --[[ Line: 7 | Upvalues: mergeDeep (copy) ]]
		local v1 = mergeDeep({
			hello = "roblox",
			goodbye = {
				world = "world"
			}
		}, {
			goodbye = {
				world = "hello"
			}
		})

		expect(v1).to.be.a("table")
		expect(v1.hello).to.equal("roblox")
		expect(v1.goodbye.world).to.equal("hello")
	end)
	it("should not modify the original dictionaries", function() --[[ Line: 20 | Upvalues: mergeDeep (copy) ]]
		local t = {
			hello = "roblox",
			goodbye = {
				world = "world"
			}
		}
		local t2 = {
			goodbye = {
				world = "hello"
			}
		}

		mergeDeep(t, t2)
		expect(t).to.be.a("table")
		expect(t2).to.be.a("table")
		expect(t.hello).to.equal("roblox")
		expect(t.goodbye.world).to.equal("world")
	end)
	it("should accept nil values", function() --[[ Line: 33 | Upvalues: mergeDeep (copy) ]]
