		expect(v1[1]).to.equal(1)
		expect(v1[2]).to.equal(4)
		expect(v1[3]).to.equal(5)
	end)
	it("should insert the given values into the given array with a negative index", function() --[[ Line: 16 | Upvalues: splice (copy) ]]
		local v1 = splice({ 1, 2, 3 }, -2, 0, 4, 5)

