local function f3(p1) --[[ Line: 31 | Upvalues: v1 (copy) ]]
	print("explosive")

	local LocalPlayer = game.Players.LocalPlayer
	local Character = LocalPlayer.Character

	if not (Character and Character.Parent) then
		return
	end

	local HumanoidRootPart = Character:FindFirstChild("HumanoidRootPart")

	if HumanoidRootPart == nil then
		return
	end

	local Unit = (HumanoidRootPart.Position - v1.Position).Unit
	local Magnitude = (HumanoidRootPart.Position - v1.Position).Magnitude

	print(Magnitude)
	print(p1)

	if not (Magnitude <= p1.Range * 2) then
		return
	end

	if Magnitude < p1.Range or LocalPlayer == p1.Exploder and p1.KillThatGuy then
		v1.ClientEvent:FireServer("Kill", {
			Direction = Unit
		})
	end

	if not (Magnitude <= p1.Range * 2) then
		return
	end

	HumanoidRootPart.Velocity = HumanoidRootPart.Velocity + Unit * (p1.Range * 4 - Magnitude) * 2 * p1.VelocityMultiplier
end

