		expect(v1[2][2]).to.equal("b")
		expect(v1[3]).to.be.a("table")
		expect(v1[3][1]).to.equal(3)
		expect(v1[3][2]).to.equal("c")
	end)
	it("should not modify the original arrays", function() --[[ Line: 27 | Upvalues: zipAll (copy) ]]
		local t = { 1, 2, 3 }
		local t2 = { "a", "b", "c" }

		zipAll(t, t2)
