		expect(#t).to.equal(3)
		expect(t[1]).to.equal(1)
		expect(t[2]).to.equal(2)
		expect(t[3]).to.equal(3)
		expect(t2).to.be.a("table")
		expect(#t2).to.equal(3)
		expect(t2[1]).to.equal("a")
		expect(t2[2]).to.equal("b")
		expect(t2[3]).to.equal("c")
	end)
	it("should fill in the blanks with None", function() --[[ Line: 48 | Upvalues: zipAll (copy), None (copy) ]]
		local v1 = zipAll({ 1, 2, 3 }, { "a", "b" })

		expect(v1).to.be.a("table")
