		expect(v1[1]).to.be.a("table")
		expect(v1[1][1]).to.equal(1)
		expect(v1[1][2]).to.equal("a")
		expect(v1[2]).to.be.a("table")
		expect(v1[2][1]).to.equal(2)
		expect(v1[2][2]).to.equal("b")
		expect(v1[3]).to.be.a("table")
