-- StarterGui.Notify.NotifyHandler
--
local ReplicatedStorage = game:GetService("ReplicatedStorage")
local RunService = game:GetService("RunService")
local TweenService = game:GetService("TweenService")
local t = {}

local function onNotifyReceived(p1, p2, p3) --[[ onNotifyReceived | Line: 7 | Upvalues: t (copy) ]]
	table.insert(t, {
		title = p1,
		description = p2,
		duration = p3 or 8
	})
end

ReplicatedStorage:WaitForChild("Events").Notify.OnClientEvent:Connect(onNotifyReceived)
ReplicatedStorage:WaitForChild("Events").NotifyBindable.Event:Connect(onNotifyReceived)

local Notification = script.Parent:WaitForChild("Container"):WaitForChild("Notification")
local v1 = TweenService:Create(Notification, TweenInfo.new(0.3, Enum.EasingStyle.Sine, Enum.EasingDirection.Out), {
	GroupTransparency = 0,
	Position = UDim2.new()
})
local v2 = TweenService:Create(Notification, TweenInfo.new(0.3, Enum.EasingStyle.Sine, Enum.EasingDirection.In), {
	GroupTransparency = 1,
	Position = UDim2.fromScale(0, 0.5)
})

Notification.GroupTransparency = 1
Notification.Position = UDim2.fromScale(0, 0.5)

while true do
	while not (#t > 0) do
		RunService.RenderStepped:Wait()
	end

	local v3 = table.remove(t, 1)

	Notification.Content.Title.Text = v3.title

	if string.find(string.lower(v3.title), "progression event") == nil then
		Notification.Background.BackgroundColor3 = Color3.fromRGB(53, 3, 139)
		Notification.Background.UIStroke.Color = Color3.fromRGB(53, 3, 139)
	else
		Notification.Background.BackgroundColor3 = Color3.fromRGB(139, 4, 116)
		Notification.Background.UIStroke.Color = Color3.fromRGB(139, 4, 116)
	end

	local v4 = v3.description or ""

	Notification.Content.Description.Text = v4
	Notification.Content.Description.Visible = if v4 == "" then false else true
	v1:Play()
	task.wait(v3.duration)
	v2:Play()
	v2.Completed:Wait()
end

