			hello = "roblox",
			goodbye = "world"
		}, "goodbye")

		expect(v1).to.be.a("table")
		expect(v1.hello).to.equal("roblox")
		expect(v1.goodbye).to.equal(nil)
	end)
	it("should not modify the original dictionary", function() --[[ Line: 15 | Upvalues: removeKey (copy) ]]
		local t = {
			hello = "roblox",
			goodbye = "world"
		}

		removeKey(t, "goodbye")
		expect(t).to.be.a("table")
		expect(t.hello).to.equal("roblox")
		expect(t.goodbye).to.equal("world")
	end)
end

