-- ReplicatedFirst.ClientModules.LyricsHandler
--
local t = {}
local RunService = game:GetService("RunService")

t.ActiveLyricChanged = require(game.ReplicatedStorage.SharedModules.Core.Lib.FastSignal).new()

local v1 = nil
local v2 = nil
local v3 = nil
local v4 = false
local v5 = 0
local t2 = {}

function ParseTimestamp(p1) --[[ ParseTimestamp | Line: 41 ]]
	local v1 = p1:split(":")
	local count = 0
	local sum = 0

	for i = #v1, 1, -1 do
		sum = sum + (tonumber(v1[i]) or 0) * math.pow(60, count)
		count = count + 1
	end

	return sum
end
function ParseSBV(p1) --[[ ParseSBV | Line: 57 ]]
	local v1 = nil
	local t = {}

	for v2, v3 in p1:split("\n") do
		if v3 ~= "" then
			if v1 then
				v1.Text = v3
				table.insert(t, v1)
				v1 = nil

				continue
			end

			local v4 = v3:split(",")

			assert(#v4 == 2, "Invalid lyric")
			v1 = {
				Text = "PARSE FAIL",
				Start = ParseTimestamp(v4[1]),
				End = ParseTimestamp(v4[2])
			}
		end
	end

	return t
end
