-- ReplicatedStorage.SharedModules.Core.Lib.Sift.Array.flatten.spec
--
return function() --[[ Line: 1 ]]
	local flatten = require(script.Parent.flatten)

	it("should return a flattened array", function() --[[ Line: 4 | Upvalues: flatten (copy) ]]
		local v1 = flatten({
			1,
			2,
			{ 3, 4 }
		})

		expect(v1).to.be.a("table")
		expect(#v1).to.equal(4)
		expect(v1[1]).to.equal(1)
		expect(v1[2]).to.equal(2)
		expect(v1[3]).to.equal(3)
		expect(v1[4]).to.equal(4)
	end)
	it("should not flatten nested arrays if depth = 0", function() --[[ Line: 18 | Upvalues: flatten (copy) ]]
		local t = {
			1,
			2,
			{ 3, 4 }
		}
		local v1 = flatten(t, 0)

		expect(v1).to.be.a("table")
		expect(#v1).to.equal(3)
		expect(v1[1]).to.equal(1)
		expect(v1[2]).to.equal(2)
		expect(v1[3]).to.equal(t[3])
	end)
	it("should flatten as deeply as possible", function() --[[ Line: 31 | Upvalues: flatten (copy) ]]
		local v1 = flatten({
			1,
			2,
			{
				3,
				4,
				{
					5,
					6,
					{ 7, 8 }
				}
			}
		})

		expect(v1).to.be.a("table")
		expect(#v1).to.equal(8)
		expect(v1[1]).to.equal(1)
		expect(v1[2]).to.equal(2)
		expect(v1[3]).to.equal(3)
		expect(v1[4]).to.equal(4)
		expect(v1[5]).to.equal(5)
		expect(v1[6]).to.equal(6)
		expect(v1[7]).to.equal(7)
		expect(v1[8]).to.equal(8)
	end)
end

