	it("should return a new dictionary with the given value removed", function() --[[ Line: 4 | Upvalues: removeValue (copy) ]]
		local v1 = removeValue({
			hello = "roblox",
			goodbye = "world"
		}, "world")

		expect(v1).to.be.a("table")
		expect(v1.hello).to.equal("roblox")
		expect(v1.goodbye).to.equal(nil)
	end)
	it("should not modify the original dictionary", function() --[[ Line: 15 | Upvalues: removeValue (copy) ]]
		local t = {
			hello = "roblox",
			goodbye = "world"
		}

		removeValue(t, "world")
		expect(t).to.be.a("table")
		expect(t.hello).to.equal("roblox")
		expect(t.goodbye).to.equal("world")
	end)
end

