-- ReplicatedStorage.SharedModules.Core.Lib.Sift.Dictionary.flatten.spec
--
return function() --[[ Line: 1 ]]
	local flatten = require(script.Parent.flatten)

	it("should return a flattened dictionary", function() --[[ Line: 4 | Upvalues: flatten (copy) ]]
		local v1 = flatten({
			hello = "world",
			goodbye = {
				yes = "no",
				no = "yes"
			}
		})

		expect(v1).to.be.a("table")
		expect(v1.hello).to.equal("world")
		expect(v1.yes).to.equal("no")
		expect(v1.no).to.equal("yes")
	end)
	it("should not flatten nested dictionaries if depth = 0", function() --[[ Line: 22 | Upvalues: flatten (copy) ]]
		local t = {
			hello = "world",
			goodbye = {
				yes = "no",
				no = "yes"
			}
		}
		local v1 = flatten(t, 0)

		expect(v1).to.be.a("table")
		expect(v1.hello).to.equal("world")
		expect(v1.goodbye).to.equal(t.goodbye)
	end)
	it("should flatten as deeply as possible", function() --[[ Line: 39 | Upvalues: flatten (copy) ]]
		local v1 = flatten({
			hello = "world",
			goodbye = {
				yes = "no",
				no = "yes",
				maybe = {
					maybe = "ok",
					okay = {
						experience = "roblox"
					}
				}
			}
		})

		expect(v1).to.be.a("table")
		expect(v1.hello).to.equal("world")
		expect(v1.yes).to.equal("no")
		expect(v1.no).to.equal("yes")
		expect(v1.maybe).to.equal("ok")
		expect(v1.experience).to.equal("roblox")
	end)
end

