-- ReplicatedStorage.SharedModules.Core.Lib.Sift.Array.removeValue
--
return function(p1, p2) --[[ removeValue | Line: 18 ]]
	local t = {}

	for i, v in ipairs(p1) do
		if v ~= p2 then
			table.insert(t, v)
		end
	end

	return t
end

-- ReplicatedStorage.SharedModules.Core.Lib.Sift.Dictionary.fromArrays
--
return function(p1, p2) --[[ fromArrays | Line: 20 ]]
	local t = {}

	for i = 1, #p1 do
		t[p1[i]] = p2[i]
	end

	return t
end

