		expect(findLast({ 1, 2, 3 }, 2, -1)).to.equal(2)
	end)
end

-- Players.Noriko_Ellen.PlayerScripts.Floor
--
local CurrentCamera = workspace.CurrentCamera

task.spawn(function() --[[ Line: 3 | Upvalues: CurrentCamera (copy) ]]
	while true do
		while true do
			task.wait()

			if not workspace:WaitForChild("BodyCatcher").Highlight.Enabled then
				break
			end

			local BodyCatcher = workspace:WaitForChild("BodyCatcher")

			BodyCatcher.Position = Vector3.new(CurrentCamera.Focus.Position.X, -620, CurrentCamera.Focus.Position.Z)
		end

		workspace:WaitForChild("BodyCatcher").Position = Vector3.new(0, 50000000, 0)
	end
end)

